+        FROM protein_domains
+        WHERE phage_id = ?
+        ORDER BY start ASC
+      `);
+      const results = this.execStatement<ProteinDomain>(stmt, [phageId]);
+      stmt.free();
+      this.cache.set(cacheKey, { data: results, timestamp: Date.now() });
+      return results;
+    } catch {
+      // Table may not exist yet
+      return [];
+    }
+  }
